    """
    result = False
    for number_1 in numbers:
        for number_2 in numbers:
            diff = abs(number_1 - number_2)
            if diff == 0.0:
                pass
            elif diff == threshold:
                result = True
            elif diff < threshold:
                pass
            else:
                break

        if result:
            break

    return result

