def flip_case(string: str) -> str:
    """ For a given string, flip lowercase characters to uppercase and uppercase to lowercase.
    >>> flip_case('Hello')
    'hELLO'
    """
    newstring = []
    for c in string:
        if c.islower():
            newstring.append(c.upper())
        else:
            newstring.append(c.lower())
    return ''.join(newstring)
