def correct_bracketing(brackets: str):
    """ brackets is a string of "(" and ")".
    return True if every opening bracket has a corresponding closing bracket.

    >>> correct_bracketing("(")
    False
    >>> correct_bracketing("()")
    True
    >>> correct_bracketing("(()())")
    True
    >>> correct_bracketing(")(()")
    False
    """
    count_brackets = {}  # dict of {open_brackets: close_brackets}

    for c in brackets:
        if c == "(" or c == ")":
            # check if it is a closing bracket
            if count_brackets.get(c) is None:
                # opening bracket
                count_brackets[c] = 1
            else:
                # closing bracket
                count_brackets[c] -= 1

    return count_brackets.get("(") == count_brackets.get(")")

def correct_bracketing(brackets: str):
    """ brackets is a string of "(" and ")".
    return True if every opening bracket has a corresponding closing bracket.

    >>> correct_bracketing("(")
    False
    >>> correct_bracketing("()")
    True
    >>> correct_bracketing("(()())")
    True
    >>> correct_bracketing(")(()")
    False
    """
    count_brackets = {}  # dict of {open_brackets: count_brackets}

    for c in brackets:
        if c == ")":
            # check if count_brackets contains an opening bracket to match this bracket to,
            # If true count_brackets - 1, else count_brackets = 0
            # If all brackets in count_brackets = 0 the function will return True
            # If all brackets in count_brackets = False the function will return False
            for opening_brackets in count_brackets.keys():
                if count_brackets[opening_brackets] > 0:
                    count_brackets[opening_brackets] -= 1

    return all(value == 0 for value in count_brackets.values())

def circular_shift(x, shift):
    """Circular shift the digits of the integer x, shift the digits right by shift
    and return the result as a string.
    If shift > number of digits, return digits reversed.
    >>> circular_shift(12, 1)
    "21"
    >>> circular_shift(12, 2)
    "12"
    """
    result = []
    str_x = str(x)
    str_x = str_x.zfill(max(len(str_x), abs(shift)))

    if shift == 0:
        return str_x
    else:
        for digit in str_x:
            result.append(digit)
        for digit in range(abs(shift)):
            result.append(result[-1])

    return ''.join(result[-shift:])

def fruit_distribution(s,n):
    """
    In this task, you will be given a string that represents a number of apples and oranges 
    that are distributed in a basket of fruit this basket contains 
    apples, oranges, and mango fruits. Given the string that represents the total number of 
    the oranges and apples and an integer that represent the total number of the fruits 
    in the basket return the number of the mango fruits in the basket.
    for examble:
    fruit_distribution("5 apples and 6 oranges", 19) ->19 - 5 - 6 = 8
    fruit_distribution("0 apples and 1 oranges",3) -> 3 - 0 - 1 = 2
    fruit_distribution("2 apples and 3 oranges", 100) -> 100 - 2 - 3 = 95
    fruit_distribution("100 apples and 1 oranges",120) -> 120 - 100 - 1 = 19
    """
    fruits_dict={'apples':int(s.split()[0]),'oranges':int(s.split()[3].rstrip('.'))}
    fruits_dict_copy={k:v for k,v in fruits_dict.items()}

    return fruits_dict_copy['apples']+fruits_dict_copy['oranges']+n-min(fruits_dict_copy, key=fruits_dict_copy.get)

